sql:
SELECT arrest_date, charge_id
FROM arrest_records
ORDER BY arrest_date DESC;

SELECT unit_name
FROM law_enforcement_units
WHERE unit_id = 1;

SELECT race, address_city
FROM arrestees
WHERE arrestee_id = 0;

SELECT arrestee_id, race, address_city, contact_phone
FROM arrestees
WHERE race = 'W';

SELECT COUNT(arrest_id) 
FROM arrest_records 
WHERE arrest_location_id = (SELECT location_id FROM arrest_locations WHERE location_city = 'NEW CANEY');

SELECT DISTINCT arrest_type
FROM arrest_records
ORDER BY arrest_type;

external_knowledge:
- 'Convicted' and 'Dismissed' are the outcome types that indicate the final result of a case; 
- 'COMM' and 'DISM' are the disposition types that represent communication and dismissal, respectively; 
- Traffic stops are a type of arrest where the police stop a vehicle for a suspected violation; 
- Charge codes are used to categorize different types of charges.

